import React, { useState } from 'react';
import axios from 'axios';

const StartPage = ({ onQuizStart }) => {
  const [formData, setFormData] = useState({
    teamName: '',
    teamLeaderName: '',
    teamLeaderEmail: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const validateEmail = (email) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.teamName.trim() || !formData.teamLeaderName.trim() || !formData.teamLeaderEmail.trim()) {
      setError('All fields are required');
      return;
    }

    if (!validateEmail(formData.teamLeaderEmail)) {
      setError('Please enter a valid email');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const response = await axios.post('http://localhost:8000/start-quiz', {
        team_name: formData.teamName,
        team_leader_name: formData.teamLeaderName,
        team_leader_email: formData.teamLeaderEmail
      });

      onQuizStart(response.data.quiz_id, formData);

    } catch (err) {
      setError(err.response?.data?.detail || 'Failed to start quiz');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      maxWidth: '450px',
      margin: '60px auto',
      padding: '30px',
      backgroundColor: 'white',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif'
    }}>
      <h1 style={{ fontSize: '28px', marginBottom: '10px', color: '#111' }}>Quiz Registration</h1>
      <p style={{ color: '#666', marginBottom: '30px', fontSize: '15px' }}>
        25 questions • 30 minutes
      </p>

      <form onSubmit={handleSubmit}>
        <div style={{ marginBottom: '20px' }}>
          <label style={{ display: 'block', marginBottom: '6px', color: '#333', fontSize: '14px' }}>
            Team Name
          </label>
          <input
            type="text"
            value={formData.teamName}
            onChange={(e) => setFormData({...formData, teamName: e.target.value})}
            style={{
              width: '100%',
              padding: '10px',
              border: '1px solid #d1d5db',
              borderRadius: '4px',
              fontSize: '15px'
            }}
          />
        </div>

        <div style={{ marginBottom: '20px' }}>
          <label style={{ display: 'block', marginBottom: '6px', color: '#333', fontSize: '14px' }}>
            Team Leader Name
          </label>
          <input
            type="text"
            value={formData.teamLeaderName}
            onChange={(e) => setFormData({...formData, teamLeaderName: e.target.value})}
            style={{
              width: '100%',
              padding: '10px',
              border: '1px solid #d1d5db',
              borderRadius: '4px',
              fontSize: '15px'
            }}
          />
        </div>

        <div style={{ marginBottom: '25px' }}>
          <label style={{ display: 'block', marginBottom: '6px', color: '#333', fontSize: '14px' }}>
            Email
          </label>
          <input
            type="email"
            value={formData.teamLeaderEmail}
            onChange={(e) => setFormData({...formData, teamLeaderEmail: e.target.value})}
            style={{
              width: '100%',
              padding: '10px',
              border: '1px solid #d1d5db',
              borderRadius: '4px',
              fontSize: '15px'
            }}
          />
        </div>

        {error && (
          <div style={{ color: '#dc2626', marginBottom: '15px', fontSize: '14px' }}>
            {error}
          </div>
        )}

        <button
          type="submit"
          disabled={loading}
          style={{
            width: '100%',
            padding: '12px',
            backgroundColor: loading ? '#9ca3af' : '#2563eb',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            fontWeight: '500',
            cursor: loading ? 'not-allowed' : 'pointer'
          }}
        >
          {loading ? 'Starting...' : 'Continue to Rules'}
        </button>
      </form>
    </div>
  );
};

export default StartPage;
